module shift_register_16bit (
  input clk,
  input reset,
  input [15:0] parallel_in,
  output [15:0] parallel_out
);
  reg [15:0] data;
  always @(posedge clk) begin
    if (reset) data <= 16'b0;
    else data <= parallel_in;
  end
  assign parallel_out = data;
endmodule

module datapath (
  input clk,
  input rst,
  input [15:0] input_bus,
  output [15:0] output_bus
);
  shift_register_16bit sreg (
    .clk(clk),
    .reset(rst),
    .parallel_in(input_bus)
  );
  assign output_bus = 16'b0;
endmodule

